using System.ComponentModel;
using System.Net;
using System.Text;
using System.Text.RegularExpressions;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using OpenAI;

// --- Configuration ---
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable.");

var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL")
    ?? "gpt-4o-mini-2024-07-18";

// --- Build AI client ---
IChatClient chatClient = new OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

// --- Register tools ---
var noteStore = new NoteStore();
var webSearchTool = new WebSearchTool();

var tools = new List<AITool>
{
    AIFunctionFactory.Create(webSearchTool.SearchAsync),
    AIFunctionFactory.Create(webSearchTool.FetchPageAsync),
    AIFunctionFactory.Create(noteStore.SaveNote),
    AIFunctionFactory.Create(noteStore.GetAllNotes),
};

// --- Create agent ---
var agent = new ChatClientAgent(
    chatClient,
    instructions: """
        You are a research agent. When given a topic:
        1. Search the web using different queries to gather diverse perspectives (2-3 searches).
        2. Fetch specific pages to read more detail when search snippets aren't enough.
        3. Save key findings as notes using the note-taking tool, including source URLs.
        4. After gathering enough information, retrieve all your notes and produce a
           well-structured summary with key points and source attribution.
        Be thorough but concise. Always cite your sources.
        """,
    name: "ResearchAgent",
    description: "An agent that researches topics using web search and note-taking tools",
    tools: tools);

// --- Interactive loop ---
Console.WriteLine("🔬 Research Agent Ready");
Console.WriteLine($"   Model: {modelId}");
Console.WriteLine("   Enter a topic to research (or 'quit' to exit)");
Console.WriteLine();

while (true)
{
    Console.Write("> ");
    var topic = Console.ReadLine()?.Trim();
    if (string.IsNullOrEmpty(topic) ||
        topic.Equals("quit", StringComparison.OrdinalIgnoreCase))
    {
        break;
    }

    noteStore.Clear();

    var session = await agent.CreateSessionAsync(conversationId: Guid.NewGuid().ToString());
    var runOptions = new ChatClientAgentRunOptions(new ChatOptions
    {
        Temperature = 0f,
        MaxOutputTokens = 4096,
    });

    Console.WriteLine();
    Console.WriteLine($"Researching: {topic}");
    Console.WriteLine(new string('─', 60));

    await foreach (var update in agent.RunStreamingAsync(
        $"Research the following topic and provide a comprehensive summary: {topic}",
        session,
        runOptions))
    {
        if (!string.IsNullOrEmpty(update.Text))
        {
            Console.Write(update.Text);
        }
    }

    Console.WriteLine();
    Console.WriteLine(new string('─', 60));
    Console.WriteLine();
}

// =============================================================================
// Tool implementations
// =============================================================================

/// <summary>Searches the web via DuckDuckGo HTML and fetches page content.</summary>
sealed partial class WebSearchTool
{
    private readonly HttpClient _httpClient = new()
    {
        Timeout = TimeSpan.FromSeconds(15),
        DefaultRequestHeaders =
        {
            { "User-Agent", "Mozilla/5.0 (compatible; ResearchAgent/1.0)" }
        },
    };

    [Description("Search the web for a query. Returns a list of result titles, URLs, and snippets.")]
    public async Task<string> SearchAsync(
        [Description("The search query")] string query,
        CancellationToken cancellationToken = default)
    {
        try
        {
            var encoded = WebUtility.UrlEncode(query);
            var url = $"https://html.duckduckgo.com/html/?q={encoded}";
            var html = await _httpClient.GetStringAsync(url, cancellationToken);

            var results = ParseSearchResults(html);
            if (results.Count == 0)
                return "No results found.";

            var sb = new StringBuilder();
            for (var i = 0; i < Math.Min(results.Count, 5); i++)
            {
                var (title, link, snippet) = results[i];
                sb.AppendLine($"[{i + 1}] {title}");
                sb.AppendLine($"    URL: {link}");
                sb.AppendLine($"    {snippet}");
                sb.AppendLine();
            }

            return sb.ToString();
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}";
        }
    }

    [Description("Fetch the text content of a web page given its URL.")]
    public async Task<string> FetchPageAsync(
        [Description("The URL to fetch")] string url,
        CancellationToken cancellationToken = default)
    {
        try
        {
            var html = await _httpClient.GetStringAsync(url, cancellationToken);
            var text = StripHtml(html);

            // Truncate to keep within reasonable token limits
            const int maxChars = 4000;
            if (text.Length > maxChars)
                text = text[..maxChars] + "\n...[truncated]";

            return text;
        }
        catch (Exception ex)
        {
            return $"Failed to fetch page: {ex.Message}";
        }
    }

    private static List<(string Title, string Url, string Snippet)> ParseSearchResults(string html)
    {
        var results = new List<(string, string, string)>();

        var titleMatches = ResultTitleRegex().Matches(html);
        var snippetMatches = SnippetRegex().Matches(html);

        for (var i = 0; i < titleMatches.Count && i < snippetMatches.Count; i++)
        {
            var link = WebUtility.HtmlDecode(titleMatches[i].Groups[1].Value);
            var title = WebUtility.HtmlDecode(StripHtml(titleMatches[i].Groups[2].Value));
            var snippet = WebUtility.HtmlDecode(StripHtml(snippetMatches[i].Groups[1].Value));

            if (!string.IsNullOrWhiteSpace(title) && link.StartsWith("http"))
            {
                results.Add((title.Trim(), link.Trim(), snippet.Trim()));
            }
        }

        return results;
    }

    private static string StripHtml(string html)
    {
        var text = HtmlTagRegex().Replace(html, " ");
        text = WhitespaceRegex().Replace(text, " ");
        return text.Trim();
    }

    [GeneratedRegex("""<a[^>]+href="([^"]*)"[^>]*class="result__a"[^>]*>(.*?)</a>""", RegexOptions.Singleline)]
    private static partial Regex ResultTitleRegex();

    [GeneratedRegex("""<a[^>]+class="result__snippet"[^>]*>(.*?)</a>""", RegexOptions.Singleline)]
    private static partial Regex SnippetRegex();

    [GeneratedRegex("<[^>]+>")]
    private static partial Regex HtmlTagRegex();

    [GeneratedRegex(@"\s+")]
    private static partial Regex WhitespaceRegex();
}

/// <summary>In-memory note store for the research agent.</summary>
sealed class NoteStore
{
    private readonly List<(string Title, string Content)> _notes = [];

    [Description("Save a research note with a title and content. Use this to record key findings.")]
    public string SaveNote(
        [Description("Short title for the note")] string title,
        [Description("The note content, including source URLs")] string content)
    {
        _notes.Add((title, content));
        return $"Note saved: \"{title}\" (total notes: {_notes.Count})";
    }

    [Description("Retrieve all saved research notes.")]
    public string GetAllNotes()
    {
        if (_notes.Count == 0)
            return "No notes saved yet.";

        var sb = new StringBuilder();
        for (var i = 0; i < _notes.Count; i++)
        {
            sb.AppendLine($"=== Note {i + 1}: {_notes[i].Title} ===");
            sb.AppendLine(_notes[i].Content);
            sb.AppendLine();
        }

        return sb.ToString();
    }

    public void Clear() => _notes.Clear();
}

